#!/usr/bin/env node
/**
 * 2026-04-30 robots.txt safety guard.
 *
 * robots.txt is dynamically generated by app/robots.ts. The disallow
 * list protects sensitive surfaces from being crawled — auth-gated
 * routes (/app, /admin), API endpoints (/api), Next internals
 * (/_next). If any of these accidentally falls off the disallow
 * list, search engines could index login pages, admin dashboards,
 * or even private API responses.
 *
 * This guard parses app/robots.ts and asserts:
 *   1. /api/, /app/, /admin/, /_next/ are all in the disallow list
 *   2. The sitemap reference is set
 *   3. Allow: / is set (otherwise the whole site gets blocked)
 *
 * It also verifies a small set of "must-be-crawlable" paths are NOT
 * accidentally in disallow:
 *   - /tools (the index)
 *   - /pricing (funnel-critical)
 *   - /blog (content marketing)
 *
 * Output line conforms to the aggregator regex
 * `${name}: ${pass} passed, ${fail} failed`.
 */

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, "..");

let passed = 0;
let failed = 0;
const failures = [];

function assert(cond, msg) {
  if (cond) passed++;
  else {
    failed++;
    failures.push(msg);
  }
}

const ROBOTS_FILE = path.join(ROOT, "app", "robots.ts");
assert(
  fs.existsSync(ROBOTS_FILE),
  "app/robots.ts must exist (Next.js renders /robots.txt from this file)",
);
if (!fs.existsSync(ROBOTS_FILE)) {
  console.log("robots-config: 0 passed, 1 failed (of 1) [app/robots.ts missing]");
  process.exit(1);
}

const ROBOTS_SRC = fs.readFileSync(ROBOTS_FILE, "utf8");

// ---------------------------------------------------------------------------
// Section A — required disallow patterns must be present.
// ---------------------------------------------------------------------------

const REQUIRED_DISALLOW = [
  { pattern: "/api/", reason: "API endpoints expose internal data shapes; not for crawlers" },
  { pattern: "/app/", reason: "auth-gated user dashboard; would expose private surfaces if indexed" },
  { pattern: "/admin/", reason: "admin-only routes; CRITICAL — never expose to crawlers" },
  { pattern: "/_next/", reason: "Next.js internals (chunks, manifests); no SEO value, wastes crawl budget" },
];

for (const d of REQUIRED_DISALLOW) {
  // Match within the disallow array literal. Accept either single-
  // or double-quoted string forms.
  const re = new RegExp(`disallow:\\s*\\[[^\\]]*['"]${d.pattern.replace(/\//g, "\\/")}['"]`, "i");
  assert(
    re.test(ROBOTS_SRC),
    `Missing required disallow pattern "${d.pattern}" in app/robots.ts. Reason: ${d.reason}`,
  );
}

// ---------------------------------------------------------------------------
// Section B — paths that MUST NOT be in disallow.
// ---------------------------------------------------------------------------

const MUST_BE_CRAWLABLE = [
  { pattern: "/tools", reason: "tool index — primary SEO funnel" },
  { pattern: "/pricing", reason: "pricing — funnel-critical conversion page" },
  { pattern: "/blog", reason: "blog — content-marketing crawlability" },
  { pattern: "/help", reason: "help center — long-tail SEO" },
];

// Extract the disallow array body so we can scan it without false-
// positive matches against URLs in comments or other strings.
const disallowMatch = /disallow:\s*\[([^\]]*)\]/i.exec(ROBOTS_SRC);
const disallowBody = disallowMatch ? disallowMatch[1] : "";

for (const c of MUST_BE_CRAWLABLE) {
  // Whole-token match on quoted strings — disallow: ["/tools", ...]
  // would accidentally block the entire SEO funnel.
  const re = new RegExp(`['"]${c.pattern.replace(/\//g, "\\/")}['"]`);
  assert(
    !re.test(disallowBody),
    `CRITICAL: "${c.pattern}" is in robots.ts disallow list. Reason: ${c.reason}. Remove from disallow array immediately.`,
  );
}

// ---------------------------------------------------------------------------
// Section C — sitemap reference + allow root.
// ---------------------------------------------------------------------------

assert(
  /sitemap:\s*[`'"]/.test(ROBOTS_SRC),
  "app/robots.ts is missing the `sitemap:` field. Without it, crawlers don't know where to find sitemap.xml. Add `sitemap: \\`${SITE_URL}/sitemap.xml\\``.",
);

assert(
  /allow:\s*['"]\/['"]/.test(ROBOTS_SRC),
  "app/robots.ts is missing `allow: \"/\"`. Without it, the disallow patterns might block the whole site (depends on robots.txt parser implementation).",
);

// ---------------------------------------------------------------------------
// Section D — sanity self-tests on the regexes.
// ---------------------------------------------------------------------------

const POS_DISALLOW = `disallow: ["/api/", "/app/", "/admin/", "/_next/"]`;
const apiRe = /disallow:\s*\[[^\]]*['"]\/api\/['"]/i;
assert(apiRe.test(POS_DISALLOW), "regex catches /api/ in disallow array");

const NEG_DISALLOW_NO_API = `disallow: ["/app/", "/admin/"]`;
assert(!apiRe.test(NEG_DISALLOW_NO_API), "regex correctly fails when /api/ is missing");

// ---------------------------------------------------------------------------
// Aggregator-friendly summary.
// ---------------------------------------------------------------------------

const total = passed + failed;
console.log(
  `robots-config: ${passed} passed, ${failed} failed (of ${total})`,
);
if (failed > 0) {
  console.log("\nFAILURES:");
  for (const f of failures) console.log(`  ${f}`);
  process.exit(1);
}
process.exit(0);
